<?php
namespace App\Services\Proposal;
use App\Models\{DataValidationReview,Umkm,UmkmUpdateSubmission};use App\Services\Audit\AuditLogger;use Illuminate\Http\Request;use Illuminate\Support\Facades\DB;
class UmkmProposalService { public function createProposal(array $data, int $actorId): UmkmUpdateSubmission { $umkm=Umkm::query()->findOrFail($data['umkm_id']); return UmkmUpdateSubmission::query()->create(['umkm_id'=>$umkm->id,'submitted_by'=>$actorId,'old_data'=>['business_name'=>$umkm->business_name,'quality_status'=>$umkm->quality_status,'notes'=>$umkm->notes],'new_data'=>['business_name'=>$data['proposed_business_name'] ?? $umkm->business_name,'quality_status'=>$data['proposed_quality_status'] ?? $umkm->quality_status,'notes'=>$data['proposed_notes'] ?? $umkm->notes],'evidence_path'=>$data['evidence_path'] ?? null,'submission_payload'=>$data,'status_data'=>$data['status_data'],'submitted_at'=>now()]); } public function reviewProposal(UmkmUpdateSubmission $submission, string $decision, ?string $reviewNote, int $reviewerId, Request $request, AuditLogger $auditLogger): UmkmUpdateSubmission { return DB::transaction(function() use($submission,$decision,$reviewNote,$reviewerId,$request,$auditLogger){ $before=$submission->toArray(); $submission->update(['status_data'=>$decision,'review_notes'=>$reviewNote,'reviewed_at'=>now(),'reviewed_by'=>$reviewerId]); DataValidationReview::query()->create(['submission_id'=>$submission->id,'reviewer_id'=>$reviewerId,'decision'=>$decision,'review_note'=>$reviewNote,'reviewed_at'=>now()]); if($decision==='disetujui'){ $official=Umkm::query()->findOrFail($submission->umkm_id); $officialBefore=$official->toArray(); $official->update(['business_name'=>$submission->new_data['business_name'] ?? $official->business_name,'quality_status'=>$submission->new_data['quality_status'] ?? $official->quality_status,'notes'=>$submission->new_data['notes'] ?? $official->notes,'updated_by'=>$reviewerId]); $auditLogger->log('umkm.official.update.by_proposal_approval',$request,'umkms',$official->id,$officialBefore,$official->fresh()->toArray()); } $auditLogger->log('umkm.proposal.review',$request,'umkm_update_submissions',$submission->id,$before,$submission->fresh()->toArray()); return $submission->fresh(); }); }}
